import{_ as t,c as o,o as e,ag as r}from"./chunks/framework.DPDPlp3K.js";const m=JSON.parse('{"title":"HotSpot 虚拟机对象探秘","description":"","frontmatter":{},"headers":[],"relativePath":"02-hotspot-jvm-object.md","filePath":"02-hotspot-jvm-object.md","lastUpdated":1684977570000}'),n={name:"02-hotspot-jvm-object.md"};function s(i,a,l,c,h,p){return e(),o("div",null,a[0]||(a[0]=[r('<h1 id="hotspot-虚拟机对象探秘" tabindex="-1">HotSpot 虚拟机对象探秘 <a class="header-anchor" href="#hotspot-虚拟机对象探秘" aria-label="Permalink to &quot;HotSpot 虚拟机对象探秘&quot;">​</a></h1><h2 id="对象的内存布局" tabindex="-1">对象的内存布局 <a class="header-anchor" href="#对象的内存布局" aria-label="Permalink to &quot;对象的内存布局&quot;">​</a></h2><p>在 HotSpot 虚拟机中，对象的内存布局分为以下 3 块区域：</p><ul><li>对象头（Header）</li><li>实例数据（Instance Data）</li><li>对齐填充（Padding）</li></ul><p><img src="https://cdn-doocs.oss-cn-shenzhen.aliyuncs.com/gh/doocs/jvm@main/images/object-memory-layout.png" alt="object-memory-layout.png"></p><h3 id="对象头" tabindex="-1">对象头 <a class="header-anchor" href="#对象头" aria-label="Permalink to &quot;对象头&quot;">​</a></h3><p>对象头记录了对象在运行过程中所需要使用的一些数据：</p><ul><li>哈希码</li><li>GC 分代年龄</li><li>锁状态标志</li><li>线程持有的锁</li><li>偏向线程 ID</li><li>偏向时间戳</li></ul><p>对象头可能包含类型指针，通过该指针能确定对象属于哪个类。如果对象是一个数组，那么对象头还会包括数组长度。</p><h3 id="实例数据" tabindex="-1">实例数据 <a class="header-anchor" href="#实例数据" aria-label="Permalink to &quot;实例数据&quot;">​</a></h3><p>实例数据部分就是成员变量的值，其中包括父类成员变量和本类成员变量。</p><h3 id="对齐填充" tabindex="-1">对齐填充 <a class="header-anchor" href="#对齐填充" aria-label="Permalink to &quot;对齐填充&quot;">​</a></h3><p>用于确保对象的总长度为 8 字节的整数倍。</p><p>HotSpot VM 的自动内存管理系统要求对象的大小必须是 8 字节的整数倍。而对象头部分正好是 8 字节的倍数（1 倍或 2 倍），因此，当对象实例数据部分没有对齐时，就需要通过对齐填充来补全。</p><blockquote><p>对齐填充并不是必然存在，也没有特别的含义，它仅仅起着占位符的作用。</p></blockquote><h2 id="对象的创建过程" tabindex="-1">对象的创建过程 <a class="header-anchor" href="#对象的创建过程" aria-label="Permalink to &quot;对象的创建过程&quot;">​</a></h2><p><img src="https://cdn-doocs.oss-cn-shenzhen.aliyuncs.com/gh/doocs/jvm@main/images/new-instruction.png" alt="new-instruction"></p><h3 id="类加载检查" tabindex="-1">类加载检查 <a class="header-anchor" href="#类加载检查" aria-label="Permalink to &quot;类加载检查&quot;">​</a></h3><p>虚拟机在解析<code>.class</code>文件时，若遇到一条 new 指令，首先它会去检查常量池中是否有这个类的符号引用，并且检查这个符号引用所代表的类是否已被加载、解析和初始化过。如果没有，那么必须先执行相应的类加载过程。</p><h3 id="为新生对象分配内存" tabindex="-1">为新生对象分配内存 <a class="header-anchor" href="#为新生对象分配内存" aria-label="Permalink to &quot;为新生对象分配内存&quot;">​</a></h3><p>对象所需内存的大小在类加载完成后便可完全确定，接下来从堆中划分一块对应大小的内存空间给新的对象。分配堆中内存有两种方式：</p><ul><li><p><strong>指针碰撞</strong><br> 如果 Java <strong>堆中内存绝对规整</strong>（说明采用的是“<strong>复制算法</strong>”或“<strong>标记整理法</strong>”），空闲内存和已使用内存中间放着一个指针作为分界点指示器，那么分配内存时只需要把指针向空闲内存挪动一段与对象大小一样的距离，这种分配方式称为“<strong>指针碰撞</strong>”。</p></li><li><p><strong>空闲列表</strong><br> 如果 Java <strong>堆中内存并不规整</strong>，已使用的内存和空闲内存交错（说明采用的是<strong>标记-清除法</strong>，有碎片），此时没法简单进行指针碰撞， VM 必须维护一个列表，记录其中哪些内存块空闲可用。分配之时从空闲列表中找到一块足够大的内存空间划分给对象实例。这种方式称为“<strong>空闲列表</strong>”。</p></li></ul><h3 id="初始化" tabindex="-1">初始化 <a class="header-anchor" href="#初始化" aria-label="Permalink to &quot;初始化&quot;">​</a></h3><p>分配完内存后，为对象中的成员变量赋上初始值，设置对象头信息，调用对象的构造函数方法进行初始化。</p><p>至此，整个对象的创建过程就完成了。</p><h2 id="对象的访问方式" tabindex="-1">对象的访问方式 <a class="header-anchor" href="#对象的访问方式" aria-label="Permalink to &quot;对象的访问方式&quot;">​</a></h2><p>所有对象的存储空间都是在堆中分配的，但是这个对象的引用却是在堆栈中分配的。也就是说在建立一个对象时两个地方都分配内存，在堆中分配的内存实际建立这个对象，而在堆栈中分配的内存只是一个指向这个堆对象的指针（引用）而已。 那么根据引用存放的地址类型的不同，对象有不同的访问方式。</p><h3 id="句柄访问方式" tabindex="-1">句柄访问方式 <a class="header-anchor" href="#句柄访问方式" aria-label="Permalink to &quot;句柄访问方式&quot;">​</a></h3><p>堆中需要有一块叫做“句柄池”的内存空间，句柄中包含了对象实例数据与类型数据各自的具体地址信息。</p><p>引用类型的变量存放的是该对象的句柄地址（reference）。访问对象时，首先需要通过引用类型的变量找到该对象的句柄，然后根据句柄中对象的地址找到对象。</p><p><img src="https://cdn-doocs.oss-cn-shenzhen.aliyuncs.com/gh/doocs/jvm@main/images/handle-access.jpg" alt="handle-access"></p><h3 id="直接指针访问方式" tabindex="-1">直接指针访问方式 <a class="header-anchor" href="#直接指针访问方式" aria-label="Permalink to &quot;直接指针访问方式&quot;">​</a></h3><p>引用类型的变量直接存放对象的地址，从而不需要句柄池，通过引用能够直接访问对象。但对象所在的内存空间需要额外的策略存储对象所属的类信息的地址。</p><p><img src="https://cdn-doocs.oss-cn-shenzhen.aliyuncs.com/gh/doocs/jvm@main/images/direct-pointer.jpg" alt="direct-pointer"></p><p>需要说明的是，HotSpot 采用第二种方式，即直接指针方式来访问对象，只需要一次寻址操作，所以在性能上比句柄访问方式快一倍。但像上面所说，它需要<strong>额外的策略</strong>来存储对象在方法区中类信息的地址。</p>',35)]))}const u=t(n,[["render",s]]);export{m as __pageData,u as default};
